110:   virtual std::unique_ptr<RQ> getNextRequestInternal() PURE;
111:   virtual void handleGoodResponse(const RS& message) PURE;
112:   void handleBadResponse(const EnvoyException& e, UpdateAck& ack) {
113:     // Note that error_detail being set is what indicates that a (Delta)DiscoveryRequest is a NACK.
114:     ack.error_detail_.set_code(Grpc::Status::WellKnownGrpcStatus::Internal);
115:     ack.error_detail_.set_message(Config::Utility::truncateGrpcStatusMessage(e.what()));
